import{_ as s,c as e,o as n,ag as i}from"./chunks/framework.Cycwnjj0.js";const m=JSON.parse('{"title":"Field Naming Differences: Perl vs Rust","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/testing/comparison/FIELD_NAMING_GUIDE.md","filePath":"contributing/testing/comparison/FIELD_NAMING_GUIDE.md","lastUpdated":null}'),l={name:"contributing/testing/comparison/FIELD_NAMING_GUIDE.md"};function p(t,a,r,o,c,d){return n(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="field-naming-differences-perl-vs-rust" tabindex="-1">Field Naming Differences: Perl vs Rust <a class="header-anchor" href="#field-naming-differences-perl-vs-rust" aria-label="Permalink to &quot;Field Naming Differences: Perl vs Rust&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>exiftool-rs uses structured field names with prefixes to indicate the metadata source, while Perl ExifTool uses simplified &quot;friendly&quot; names. The actual data extracted is identical.</p><h2 id="naming-patterns" tabindex="-1">Naming Patterns <a class="header-anchor" href="#naming-patterns" aria-label="Permalink to &quot;Naming Patterns&quot;">​</a></h2><h3 id="_1-space-removal" tabindex="-1">1. Space Removal <a class="header-anchor" href="#_1-space-removal" aria-label="Permalink to &quot;1. Space Removal&quot;">​</a></h3><p>Perl uses spaces in field names, Rust uses camelCase or concatenation:</p><ul><li><code>Bits Per Sample</code> → <code>BitsPerSample</code></li><li><code>Image Width</code> → <code>ImageWidth</code></li><li><code>Strip Byte Counts</code> → <code>StripByteCounts</code></li></ul><h3 id="_2-prefixes" tabindex="-1">2. Prefixes <a class="header-anchor" href="#_2-prefixes" aria-label="Permalink to &quot;2. Prefixes&quot;">​</a></h3><p>Rust adds prefixes to show metadata source:</p><h4 id="jpeg-tiff-prefixes" tabindex="-1">JPEG/TIFF Prefixes <a class="header-anchor" href="#jpeg-tiff-prefixes" aria-label="Permalink to &quot;JPEG/TIFF Prefixes&quot;">​</a></h4><ul><li><code>IFD0:</code> - Main image metadata</li><li><code>ExifIFD:</code> - EXIF-specific data</li><li><code>XMP-dc:</code> - XMP Dublin Core</li><li><code>XMP-xmp:</code> - XMP basic schema</li></ul><p><strong>Examples:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perl: Make</span></span>
<span class="line"><span>Rust: IFD0:Make</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Perl: Creator</span></span>
<span class="line"><span>Rust: XMP-xmp:Creator</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Perl: Color Space</span></span>
<span class="line"><span>Rust: ExifIFD:ColorSpace</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h4 id="png-prefixes" tabindex="-1">PNG Prefixes <a class="header-anchor" href="#png-prefixes" aria-label="Permalink to &quot;PNG Prefixes&quot;">​</a></h4><ul><li><code>PNG:</code> - PNG chunk metadata</li><li><code>PNG-pHYs:</code> - Physical pixel dimensions</li><li><code>PNG:tEXt:</code> - Text metadata chunks</li><li><code>IFD0:</code> - Embedded EXIF metadata</li></ul><p><strong>Examples:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perl: Image Width</span></span>
<span class="line"><span>Rust: PNG:ImageWidth</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Perl: Pixels Per Unit X</span></span>
<span class="line"><span>Rust: PNG-pHYs:PixelsPerUnitX</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Perl: Datecreate</span></span>
<span class="line"><span>Rust: PNG:tEXt:date:create</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h4 id="pdf-prefixes" tabindex="-1">PDF Prefixes <a class="header-anchor" href="#pdf-prefixes" aria-label="Permalink to &quot;PDF Prefixes&quot;">​</a></h4><ul><li><code>PDF:</code> - PDF document metadata</li><li><code>Profile:</code> - ICC color profile data</li></ul><p><strong>Examples:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perl: PDF Version</span></span>
<span class="line"><span>Rust: PDF:PDFVersion</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Perl: Profile Description</span></span>
<span class="line"><span>Rust: Profile:ProfileDescription</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h4 id="mp4-quicktime-prefixes" tabindex="-1">MP4/QuickTime Prefixes <a class="header-anchor" href="#mp4-quicktime-prefixes" aria-label="Permalink to &quot;MP4/QuickTime Prefixes&quot;">​</a></h4><ul><li><code>QuickTime:</code> - QuickTime container metadata</li><li><code>ItemList:</code> - Metadata item list (user data)</li><li><code>UserData:</code> - User data atoms</li></ul><p><strong>Examples:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perl: Major Brand</span></span>
<span class="line"><span>Rust: QuickTime:MajorBrand</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Perl: Artist</span></span>
<span class="line"><span>Rust: ItemList:Artist</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="_3-friendly-name-differences" tabindex="-1">3. Friendly Name Differences <a class="header-anchor" href="#_3-friendly-name-differences" aria-label="Permalink to &quot;3. Friendly Name Differences&quot;">​</a></h3><p>Some fields have completely different names:</p><table tabindex="0"><thead><tr><th>Perl ExifTool</th><th>exiftool-rs</th><th>Notes</th></tr></thead><tbody><tr><td>Camera Model Name</td><td>Model</td><td>Perl adds &quot;Camera&quot; prefix</td></tr><tr><td>Primary Chromaticities</td><td>PrimaryChromaticities</td><td>Space removed</td></tr><tr><td>Photometric Interpretation</td><td>PhotometricInterpretation</td><td>Space removed</td></tr><tr><td>Y Cb Cr Positioning</td><td>YCbCrPositioning</td><td>Space removed</td></tr></tbody></table><h2 id="computed-fields-perl-only" tabindex="-1">Computed Fields (Perl Only) <a class="header-anchor" href="#computed-fields-perl-only" aria-label="Permalink to &quot;Computed Fields (Perl Only)&quot;">​</a></h2><p>These fields are NOT in exiftool-rs because they&#39;re computed from other metadata:</p><h3 id="image-dimensions" tabindex="-1">Image Dimensions <a class="header-anchor" href="#image-dimensions" aria-label="Permalink to &quot;Image Dimensions&quot;">​</a></h3><ul><li><strong>Image Size</strong> - Computed as &quot;Width×Height&quot; (e.g., &quot;800×600&quot;)</li><li><strong>Megapixels</strong> - Computed as (Width × Height) / 1,000,000</li></ul><p>Both Width and Height are available separately in Rust.</p><h3 id="video-fields" tabindex="-1">Video Fields <a class="header-anchor" href="#video-fields" aria-label="Permalink to &quot;Video Fields&quot;">​</a></h3><ul><li><strong>Avg Bitrate</strong> - Computed as File Size / Duration</li></ul><h3 id="diagnostic-fields" tabindex="-1">Diagnostic Fields <a class="header-anchor" href="#diagnostic-fields" aria-label="Permalink to &quot;Diagnostic Fields&quot;">​</a></h3><ul><li><strong>Warning</strong> - Validation messages (e.g., &quot;Text/EXIF chunk(s) found after PNG IDAT&quot;)</li></ul><h3 id="internal-metadata" tabindex="-1">Internal Metadata <a class="header-anchor" href="#internal-metadata" aria-label="Permalink to &quot;Internal Metadata&quot;">​</a></h3><ul><li><strong>Exif Byte Order</strong> - Indicates little-endian vs big-endian encoding</li><li><strong>File Type</strong>, <strong>File Type Extension</strong>, <strong>MIME Type</strong> - File classification</li></ul><h2 id="quick-reference-common-fields" tabindex="-1">Quick Reference: Common Fields <a class="header-anchor" href="#quick-reference-common-fields" aria-label="Permalink to &quot;Quick Reference: Common Fields&quot;">​</a></h2><h3 id="jpeg-tiff" tabindex="-1">JPEG/TIFF <a class="header-anchor" href="#jpeg-tiff" aria-label="Permalink to &quot;JPEG/TIFF&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perl                    → Rust</span></span>
<span class="line"><span>----------------------------------------</span></span>
<span class="line"><span>Make                    → IFD0:Make</span></span>
<span class="line"><span>Camera Model Name       → IFD0:Model</span></span>
<span class="line"><span>Orientation             → IFD0:Orientation</span></span>
<span class="line"><span>X Resolution            → IFD0:XResolution</span></span>
<span class="line"><span>Y Resolution            → IFD0:YResolution</span></span>
<span class="line"><span>Resolution Unit         → IFD0:ResolutionUnit</span></span>
<span class="line"><span>Artist                  → IFD0:Artist</span></span>
<span class="line"><span>Date/Time Original      → ExifIFD:DateTimeOriginal</span></span>
<span class="line"><span>Color Space             → ExifIFD:ColorSpace</span></span>
<span class="line"><span>Exif Version            → ExifIFD:ExifVersion</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h3 id="png" tabindex="-1">PNG <a class="header-anchor" href="#png" aria-label="Permalink to &quot;PNG&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perl                    → Rust</span></span>
<span class="line"><span>----------------------------------------</span></span>
<span class="line"><span>Image Width             → PNG:ImageWidth</span></span>
<span class="line"><span>Image Height            → PNG:ImageHeight</span></span>
<span class="line"><span>Bit Depth               → PNG:BitDepth</span></span>
<span class="line"><span>Color Type              → PNG:ColorType</span></span>
<span class="line"><span>Compression             → PNG:Compression</span></span>
<span class="line"><span>Interlace               → PNG:Interlace</span></span>
<span class="line"><span>Modify Date             → PNG:ModifyDate</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="pdf" tabindex="-1">PDF <a class="header-anchor" href="#pdf" aria-label="Permalink to &quot;PDF&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perl                    → Rust</span></span>
<span class="line"><span>----------------------------------------</span></span>
<span class="line"><span>PDF Version             → PDF:PDFVersion</span></span>
<span class="line"><span>Page Count              → PDF:PageCount</span></span>
<span class="line"><span>Producer                → PDF:Producer</span></span>
<span class="line"><span>Create Date             → PDF:CreateDate</span></span>
<span class="line"><span>Modify Date             → PDF:ModifyDate</span></span>
<span class="line"><span>Linearized              → PDF:Linearized</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="mp4-quicktime" tabindex="-1">MP4/QuickTime <a class="header-anchor" href="#mp4-quicktime" aria-label="Permalink to &quot;MP4/QuickTime&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perl                    → Rust</span></span>
<span class="line"><span>----------------------------------------</span></span>
<span class="line"><span>Major Brand             → QuickTime:MajorBrand</span></span>
<span class="line"><span>Compatible Brands       → QuickTime:CompatibleBrands</span></span>
<span class="line"><span>Duration                → QuickTime:Duration</span></span>
<span class="line"><span>Time Scale              → QuickTime:TimeScale</span></span>
<span class="line"><span>Title                   → ItemList:Title</span></span>
<span class="line"><span>Artist                  → ItemList:Artist</span></span>
<span class="line"><span>Album                   → ItemList:Album</span></span>
<span class="line"><span>Genre                   → ItemList:Genre</span></span>
<span class="line"><span>Copyright               → ItemList:Copyright</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="benefits-of-rust-naming-convention" tabindex="-1">Benefits of Rust Naming Convention <a class="header-anchor" href="#benefits-of-rust-naming-convention" aria-label="Permalink to &quot;Benefits of Rust Naming Convention&quot;">​</a></h2><ol><li><strong>Source Clarity</strong>: Immediately know where metadata came from (IFD0, EXIF, XMP, etc.)</li><li><strong>Namespace Prevention</strong>: Avoid conflicts when same field name exists in multiple sources</li><li><strong>Programmatic Parsing</strong>: Easier to filter/group by prefix in code</li><li><strong>Standard Compliance</strong>: Matches actual metadata structure specifications</li></ol><h2 id="backward-compatibility" tabindex="-1">Backward Compatibility <a class="header-anchor" href="#backward-compatibility" aria-label="Permalink to &quot;Backward Compatibility&quot;">​</a></h2><p>If you have scripts expecting Perl field names, you can:</p><ol><li>Strip prefixes: <code>IFD0:Make</code> → <code>Make</code></li><li>Add friendly aliases in your application layer</li><li>Use the raw field name for lookups, Rust will find it</li></ol>`,53)])])}const b=s(l,[["render",p]]);export{m as __pageData,b as default};
